const d=document.getElementById("mobile-menu-btn"),i=document.getElementById("nav-links");d?.addEventListener("click",()=>{i?.classList.toggle("active")});const l=document.getElementById("theme-toggle");function s(){const e=localStorage.getItem("theme");return e||(window.matchMedia("(prefers-color-scheme: dark)").matches?"dark":"light")}function o(e){document.documentElement.setAttribute("data-theme",e),localStorage.setItem("theme",e)}o(s());l?.addEventListener("click",()=>{const c=document.documentElement.getAttribute("data-theme")==="dark"?"light":"dark";o(c)});window.matchMedia("(prefers-color-scheme: dark)").addEventListener("change",e=>{localStorage.getItem("theme")||o(e.matches?"dark":"light")});const t=document.getElementById("back-to-top");window.addEventListener("scroll",()=>{window.scrollY>300?t?.classList.add("visible"):t?.classList.remove("visible")});t?.addEventListener("click",()=>{window.scrollTo({top:0,behavior:"smooth"})});const n=document.getElementById("cookie-banner"),a=document.getElementById("cookie-accept"),r=document.getElementById("cookie-decline");localStorage.getItem("cookie-consent")||n?.removeAttribute("hidden");a?.addEventListener("click",()=>{localStorage.setItem("cookie-consent","accepted"),n?.setAttribute("hidden","")});r?.addEventListener("click",()=>{localStorage.setItem("cookie-consent","declined"),n?.setAttribute("hidden","")});
